import React, { useMemo, useState } from "react";
import WeatherOverlay from "./WeatherOverlay";
import BottomBar from "./BottomBar";
import Chatbot from "./Chatbot";
import SearchSection from "./SearchSection";
import WeatherNow from "./WeatherNow";
import Hourly from "./Hourly";
import Forecast from "./Forecast";
import Radar from "./Radar";

// tiny safe getter
const get = (obj, path, fallback = "") =>
  path.split(".").reduce((o, k) => (o && o[k] != null ? o[k] : null), obj) ?? fallback;

/**
 * Props
 * - weatherData: { current, hourly[], daily[] }
 * - currentCondition: "clear" | "pc" | "cloudy" | "rain" | "snow" | "thunderstorm" | "fog"
 * - isNight: boolean
 * - onSearch(query): Promise<void>  (hooked to SearchSection)
 */
export default function WeatherApp({
  weatherData = {},
  currentCondition = "pc",
  isNight = false,
  onSearch = async () => {},
}) {
  const timeOfDay = isNight ? "night" : "day";
  const overlayProps = useMemo(
    () => ({ condition: currentCondition, timeOfDay }),
    [currentCondition, timeOfDay]
  );

  const [activeTab, setActiveTab] = useState("home");
  const [chatOpen, setChatOpen] = useState(false);

  const scrollToId = (id) => {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  const handleHome = () => {
    setActiveTab("home");
    setChatOpen(false);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };
  const handleForecast = () => {
    setActiveTab("forecast");
    setChatOpen(false);
    scrollToId("forecast-section");
  };
  const handleRadar = () => {
    setActiveTab("radar");
    setChatOpen(false);
    scrollToId("radar-section");
  };
  const handleChat = () => {
    setActiveTab("chat");
    setChatOpen(true);
  };

  // data slices
  const current = get(weatherData, "current", {});
  const hourly = Array.isArray(get(weatherData, "hourly", [])) ? weatherData.hourly : [];
  const daily  = Array.isArray(get(weatherData, "daily", []))  ? weatherData.daily  : [];

  return (
    <div className="relative min-h-screen flex flex-col bg-white overflow-x-hidden">
      {/* Background video overlays */}
      <div className="absolute top-0 left-0 w-full h-full z-0">
        <WeatherOverlay {...overlayProps} opacityMobile={0.5} />
      </div>

      {/* CONTENT */}
      <main className="relative z-10 flex-1">
        {/* SEARCH */}
        <section id="search-section" className="px-4 pt-4 md:pt-6 max-w-5xl mx-auto">
          <SearchSection onSearch={onSearch} />
        </section>

        {/* WEATHER NOW */}
        <section id="now-section" className="px-4 pt-4 md:pt-6 max-w-5xl mx-auto">
          <WeatherNow data={current} />
        </section>

        {/* HOURLY */}
        <section id="hourly-section" className="px-4 pt-4 md:pt-6 max-w-5xl mx-auto">
          <h2 className="text-base md:text-lg font-semibold mb-3">Hourly Forecast</h2>
          <Hourly data={hourly} />
        </section>

        {/* 16‑DAY FORECAST */}
        <section id="forecast-section" className="px-4 pt-6 pb-28 md:pb-12 max-w-5xl mx-auto">
          <h2 className="text-base md:text-lg font-semibold mb-3">16‑Day Forecast</h2>
          <Forecast data={daily} />
        </section>

        {/* RADAR */}
        <section id="radar-section" className="px-4 pb-40 md:pb-24 max-w-6xl mx-auto">
          <h2 className="text-base md:text-lg font-semibold mb-3">Radar</h2>
          <Radar />
        </section>
      </main>

      {/* Bottom bar on both mobile + desktop */}
      <BottomBar
        active={activeTab}
        onHome={handleHome}
        onForecast={handleForecast}
        onRadar={handleRadar}
        onChat={handleChat}
      />

      {/* Chat Drawer / Panel */}
      <div
        className={[
          "fixed left-0 right-0 z-50",
          "md:right-6 md:bottom-24 md:left-auto md:w-[380px]",
          chatOpen ? "bottom-0" : "-bottom-[80vh] md:bottom-24 md:opacity-0 md:pointer-events-none",
          "transition-all duration-300 ease-out",
        ].join(" ")}
        aria-hidden={!chatOpen}
      >
        <div className="mx-auto max-w-xl md:max-w-none h[75vh] md:h-[520px] rounded-t-2xl md:rounded-2xl border border-white/10 bg-white/85 backdrop-blur shadow-xl overflow-hidden">
          <div className="flex items-center gap-2 px-4 py-3 border-b border-white/20 bg-white/60">
            <div className="h-2.5 w-2.5 rounded-full bg-purple-600" />
            <div className="font-semibold text-sm">Chat</div>
            <button
              className="ml-auto text-sm px-3 py-1 rounded-lg bg-black/10 hover:bg-black/20"
              onClick={() => setChatOpen(false)}
            >
              Close
            </button>
          </div>
          <div className="h-full">
            <Chatbot
              className="h-full"
              onSend={async (message) => {
                try {
                  const r = await fetch("/api/chat", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ message }),
                  });
                  if (!r.ok) throw new Error("bad status");
                  const data = await r.json();
                  return { role: "assistant", content: data?.content ?? data?.message ?? "(no content)" };
                } catch {
                  return { role: "assistant", content: "Sorry, I had trouble reaching the server." };
                }
              }}
            />
          </div>
        </div>
      </div>
    </div>
  );
}
